  ('social-worker-moex-02401', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國98年修正的「性騷擾防治法」中，下列敘述何者錯誤？', '["該法要求30人以上之機關、部隊、學校、機構或雇用人應訂定性騷擾防治措施", "因教育、訓練等，利用權勢或機會為性騷擾者，得加重科處罰鍰至二分之一", "該法所規定之罪屬於告訴乃論", "該法規範所有場域中陌生人所進行之性騷擾事件處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02402', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國於民國 104 年通過的長期照顧服務法中，明訂應設置長照服務發展基金，下列何者並非該基金的來 源？', '["菸品健康福利捐", "政府預算撥充", "公益彩券盈餘", "基金孳息收入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02403', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列性別工作平等法中育嬰留職停薪規定之敘述，何者錯誤？', '["受僱者任職滿六個月後，於每一子女滿三歲前，得申請育嬰留職停薪，期間至該子女滿三歲止，但不 得逾二年", "受僱者於育嬰留職停薪期間，得繼續參加原有之社會保險，原由雇主負擔之保險費，免予繳納；原由 受僱者負擔之保險費，得遞延三年繳納", "依家事事件法、兒童及少年福利與權益保障法相關規定，與收養兒童先行共同生活之受僱者，其共同 生活期間無法適用育嬰留職停薪的規定", "育嬰留職停薪的規定適用於勞工、公務人員、教育人員及軍職人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02404', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於性別工作平等法中促進職場工作平等措施的規定，何者錯誤？', '["受僱者妊娠期間，雇主應給予產檢假五日。受僱者於其配偶分娩時，雇主應給予陪產假五日", "妊娠未滿二個月流產者，應使其停止工作，給予產假五日", "受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧時，得請家庭照顧假", "子女未滿一歲須受僱者親自哺乳者，雇主每日給哺乳時間，每次以三十分鐘為度。該項哺乳時間只得 於規定休息時間內為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02405', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '特殊境遇家庭扶助條例除規定申請人家庭總收入按全家人口平均分配，每人每月未超過政府當年公布最 低生活費2.5倍，及臺灣地區平均每人每月消費支出1.5倍，且家庭財產未超過中央主管機關公告之一定 金額的要件外，申請人的特殊境遇狀況，下列何者不適用？', '["單親父親", "隔代教養家庭", "經政府評估三個月內生活發生重大變故，係因債務陷入經濟困難者", "懷胎三個月以上至分娩二個月內之未婚懷孕婦女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02406', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '身心障礙者權益保障法中就業權益保障相關規定之敘述，何者正確？', '["庇護性就業服務為協助具就業意願及就業能力，而不足以獨立在競爭性就業市場工作之身心障礙者的 個別化就業安置、訓練及其他工作協助", "對具就業意願而就業能力不足、無法進入競爭性就業市場，需長期就業支持之身心障礙者，依其職業 輔導評量結果提供支持性就業服務", "各級政府機關、公立學校及公營事業機構員工總人數34人以上者，進用具有就業能力之身心障礙者人 數，不得低於員工總人數3%", "私校、團體及民營事業機構員工總人數在76人以上者，進用具有就業能力之身心障礙者人數，不得低 於員工總人數1%，且不得少於一人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02407', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬身心障礙者權益保障法規定中，直轄市、縣（市）勞工主管機關應推動設立的保障就業權 益之機構？', '["職業訓練機構", "庇護工場", "就業服務機構", "創投融資機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02408', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '全民健保為保障民眾享有就醫權益，若民眾因健保欠費遭鎖卡，依據衛生福利部中央健康保險署「弱勢 民眾安心就醫方案」若查證確屬弱勢對象得予解卡。下列何者並非該方案之協助對象？', '["低收入戶", "特殊境遇受扶助家庭", "18歲以下兒童及少年有醫療需求者", "孕婦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02409', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於普及式福利之敘述，何者錯誤？', '["基於社會效果考量，民眾透過制度受到平等的對待", "福利領受者必須經過資產調查", "能夠避免福利烙印標籤效果", "具公民權或繳納一固定數額社福基金者即享有資格"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02410', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於公益勸募條例規定的敘述，下列何者錯誤？', '["是針對以公益為目的而募集財物或接受捐贈之勸募行為及其管理的條例", "合法之勸募團體包括公立學校、行政法人、公益性社團法人及財團法人", "學生社團若已具學生學籍身分，無須再透過學校或財團法人名義申請勸募許可，即可向大眾勸募財物", "公益勸募主體需透過公開徵信保障捐款人，並規範公益勸募活動之執行與所得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
